--- ../pppd.orig/ipcp.c Sat Aug 28 05:19:03 1999
+++ ipcp.c      Sun Jan 21 04:29:10 2001
@@ -42,7 +42,7 @@
 /* global vars */
 ipcp_options ipcp_wantoptions[NUM_PPP];        /* Options that we want to
request */
 ipcp_options ipcp_gotoptions[NUM_PPP]; /* Options that peer ack'd */
-ipcp_options ipcp_allowoptions[NUM_PPP];       /* Options we allow peer to
request */
+ipcp_options ipcp_allowoptions[NUM_PPP];/* Options we allow peer to request */
 ipcp_options ipcp_hisoptions[NUM_PPP]; /* Options that we ack'd */

 /* local vars */
@@ -100,6 +100,7 @@
 static void ip_check_options __P((void));
 static int  ip_demand_conf __P((int));
 static int  ip_active_pkt __P((u_char *, int));
+static void create_resolv __P((u_int32_t, u_int32_t));

 struct protent ipcp_protent = {
     PPP_IPCP,
@@ -301,7 +302,7 @@

 #define LENCIVJ(neg, old)      (neg ? (old? CILEN_COMPRESS : CILEN_VJ) : 0)
 #define LENCIADDR(neg, old)    (neg ? (old? CILEN_ADDRS : CILEN_ADDR) : 0)
-
+#define LENCIDNS(neg)          (neg ? (CILEN_ADDR) : 0)
     /*
      * First see if we want to change our options to the old
      * forms because we have received old forms from the peer.
@@ -327,7 +328,9 @@
     }

     return (LENCIADDR(go->neg_addr, go->old_addrs) +
-           LENCIVJ(go->neg_vj, go->old_vj));
+           LENCIVJ(go->neg_vj, go->old_vj) +
+           LENCIDNS(go->req_dns1) +
+           LENCIDNS(go->req_dns2)) ;
 }


@@ -377,11 +380,28 @@
            neg = 0; \
     }

+#define ADDCIDNS(opt, neg, addr) \
+    if (neg) { \
+       if (len >= CILEN_ADDR) { \
+           u_int32_t l; \
+           PUTCHAR(opt, ucp); \
+           PUTCHAR(CILEN_ADDR, ucp); \
+           l = ntohl(addr);\
+           PUTLONG(l, ucp); \
+           len -= CILEN_ADDR; \
+       } else \
+           neg = 0; \
+    }
+
     ADDCIADDR((go->old_addrs? CI_ADDRS: CI_ADDR), go->neg_addr,
              go->old_addrs, go->ouraddr, go->hisaddr);

     ADDCIVJ(CI_COMPRESSTYPE, go->neg_vj, go->vj_protocol, go->old_vj,
            go->maxslotindex, go->cflag);
+           
+    ADDCIDNS(CI_MS_DNS1,go->req_dns1,go->dnsaddr[0]);
+    
+    ADDCIDNS(CI_MS_DNS2,go->req_dns2,go->dnsaddr[1]);

     *lenp -= len;
 }
@@ -457,11 +477,30 @@
        } \
     }

+#define ACKCIDNS(opt, neg, addr) \
+    if (neg) { \
+       u_int32_t l; \
+       if ((len -= CILEN_ADDR) < 0) \
+           goto bad; \
+       GETCHAR(citype, p); \
+       GETCHAR(cilen, p); \
+       if (cilen != CILEN_ADDR || citype != opt) \
+           goto bad; \
+       GETLONG(l, p); \
+       cilong = htonl(l);\
+       if (addr != cilong) \
+           goto bad; \
+    }
+
     ACKCIADDR((go->old_addrs? CI_ADDRS: CI_ADDR), go->neg_addr,
              go->old_addrs, go->ouraddr, go->hisaddr);

     ACKCIVJ(CI_COMPRESSTYPE, go->neg_vj, go->vj_protocol, go->old_vj,
            go->maxslotindex, go->cflag);
+           
+    ACKCIDNS(CI_MS_DNS1,go->req_dns1,go->dnsaddr[0]);
+    
+    ACKCIDNS(CI_MS_DNS2,go->req_dns2,go->dnsaddr[1]);

     /*
      * If there are any remaining CIs, then this packet is bad.
@@ -494,7 +533,7 @@
     u_char cimaxslotindex, cicflag;
     u_char citype, cilen, *next;
     u_short cishort;
-    u_int32_t ciaddr1, ciaddr2, l;
+    u_int32_t ciaddr1, ciaddr2, l, cidnsaddr;
     ipcp_options no;           /* options we've seen Naks for */
     ipcp_options try;          /* options to request next time */

@@ -537,6 +576,19 @@
         code \
     }

+#define NAKCIDNS(opt, neg, code) \
+    if (go->neg && \
+       ((cilen = p[1]) == CILEN_ADDR) && \
+       len >= cilen && \
+       p[0] == opt) { \
+       len -= cilen; \
+       INCPTR(2, p); \
+       GETLONG(l, p); \
+       cidnsaddr = htonl(l); \
+       no.neg = 1; \
+       code \
+    }
+
     /*
      * Accept the peer's idea of {our,his} address, if different
      * from our idea, only if the accept_{local,remote} flag is set.
@@ -583,6 +635,14 @@
            }
            );

+    NAKCIDNS(CI_MS_DNS1, req_dns1,
+           try.dnsaddr[0] = cidnsaddr;
+           );
+
+    NAKCIDNS(CI_MS_DNS2, req_dns2,
+           try.dnsaddr[1] = cidnsaddr;
+           );
+
     /*
      * There may be remaining CIs, if the peer is requesting negotiation
      * on an option that we didn't include in our request packet.
@@ -719,12 +779,32 @@
        try.neg = 0; \
      }

+#define REJCIDNS(opt, neg, dnsaddr) \
+    if(go->neg && \
+       ((cilen = p[1]) == CILEN_ADDR) && \
+       len >= cilen && \
+       p[0] == opt) { \
+       u_int32_t l; \
+       len -= cilen; \
+       INCPTR(2, p); \
+       GETLONG(l, p); \
+       cilong = htonl(l); \
+       /* Check rejected value. */ \
+       if (cilong != dnsaddr) \
+           goto bad; \
+       try.neg = 0; \
+    }
+
     REJCIADDR((go->old_addrs? CI_ADDRS: CI_ADDR), neg_addr,
              go->old_addrs, go->ouraddr, go->hisaddr);

     REJCIVJ(CI_COMPRESSTYPE, neg_vj, go->vj_protocol, go->old_vj,
            go->maxslotindex, go->cflag);

+    REJCIDNS(CI_MS_DNS1, req_dns1, go->dnsaddr[0]);
+
+    REJCIDNS(CI_MS_DNS2, req_dns2, go->dnsaddr[1]);
+
     /*
      * If there are any remaining CIs, then this packet is bad.
      */
@@ -1159,6 +1239,17 @@
     }
     script_setenv("IPLOCAL", ip_ntoa(go->ouraddr));
     script_setenv("IPREMOTE", ip_ntoa(ho->hisaddr));
+    
+    if (go->dnsaddr[0] || go->dnsaddr[1]) {
+       script_setenv("USEPEERDNS","1");
+       if (go->dnsaddr[0])
+           script_setenv("DNS1",ip_ntoa(go->dnsaddr[0]));
+       if (go->dnsaddr[1])
+           if (go->dnsaddr[1] != go->dnsaddr[0]) /* if addresses are not same
*/
+               script_setenv("DNS2",ip_ntoa(go->dnsaddr[1]));
+       if (update_resolv)
+           create_resolv(go->dnsaddr[0], go->dnsaddr[1]);
+    }

     /*
      * Check that the peer is allowed to use the IP address it wants.
@@ -1252,6 +1343,11 @@

        syslog(LOG_NOTICE, "local  IP address %s", ip_ntoa(go->ouraddr));
        syslog(LOG_NOTICE, "remote IP address %s", ip_ntoa(ho->hisaddr));
+       if (go->dnsaddr[0])
+           syslog(LOG_NOTICE, "primary DNS address
%s",ip_ntoa(go->dnsaddr[0]));
+       if (go->dnsaddr[1])
+           if (go->dnsaddr[1] != go->dnsaddr[0])
+               syslog(LOG_NOTICE, "secondary DNS address
%s",ip_ntoa(go->dnsaddr[1]));
     }

     /*
@@ -1353,6 +1449,33 @@
     argv[6] = ipparam;
     argv[7] = NULL;
     run_program(script, argv, 0);
+}
+
+/*
+ * create_resolve - create the replacement resolv.conf file
+ */
+static void
+create_resolv(peerdns1, peerdns2)
+    u_int32_t peerdns1, peerdns2;
+{
+    FILE *f;
+    f = fopen(_PATH_RESOLV, "w");
+    if (f == NULL) {
+       syslog(LOG_ERR, "Failed to create %s: %m", _PATH_RESOLV);
+       return;
+    }
+    
+    if (peerdns1)
+       fprintf(f, "\nnameserver %s\n", ip_ntoa(peerdns1));
+
+    if (peerdns2)
+       if (peerdns2 != peerdns1) /* if addresses are not same */
+           fprintf(f, "nameserver %s\n", ip_ntoa(peerdns2));
+
+    if (ferror(f))
+       syslog(LOG_ERR, "Write failed to %s: %m", _PATH_RESOLV);
+
+    fclose(f);
 }

