+++ upap.c      Sun Jan 21 04:28:26 2001
@@ -591,7 +591,10 @@
        printer(arg, " user=");
        print_string(user, ulen, printer, arg);
        printer(arg, " password=");
-       print_string(pwd, wlen, printer, arg);
+       if (!hide_password)
+           print_string(pwd, wlen, printer, arg);
+       else
+           printer(arg, "\"********\"");
